import React, {useMemo} from "react";
import { RadioButton as PrimeRadioButton } from "primereact/radiobutton";
import type { IRadioCheckboxListItem } from "@lmb-it/kitsconcerto-types";
import { Flex, Text } from "../../../_compat";
import { useKitsTheme } from "../../../contexts/Theme";

interface IRadioButtonProps<T> {
    item: IRadioCheckboxListItem<T>;
    selected: boolean;
    disabled?: boolean;
    isInvalid?: boolean;
    onToggle: () => void;
}

const RadioButton =<T,> ({
                            item,
                            selected,
                            disabled,
                            isInvalid,
                            onToggle,
                        }: IRadioButtonProps<T>) => {
    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');
    const dangerColor = resolveToken('danger');

    /* ---------------------------------- */
    /* Size & padding (from old component) */
    /* ---------------------------------- */
    const sizes: Record<string, number> = {
        xs: 13,
        sm: 17,
        md: 22,
        lg: 27,
        xl: 30,
    };

    const paddings: Record<string, [number, number]> = {
        xs: [1, 3],
        sm: [2, 5],
        md: [3, 7],
        lg: [4, 9],
        xl: [5, 13],
    };

    const size = item.size ? sizes[item.size] : sizes.sm;
    const padding = item.size ? paddings[item.size] : paddings.sm;

    /* ---------------------------------- */
    /* Classes (same logic as old version) */
    /* ---------------------------------- */
    const classNames = useMemo(() => {
        const classes = ["check-button"];


        if (disabled) classes.push("opacity-40");
        if (selected) classes.push("checked-option");

        if (item.component) {
            classes.push("with-component");
        } else {
            classes.push("border-round-md", "shadow-2");
        }

        if (isInvalid) classes.push("p-invalid");

        return classes.join(" ");
    }, [selected, disabled, isInvalid, item.component]);

    /* ---------------------------------- */
    /* Label positioning (same behavior)   */
    /* ---------------------------------- */
    const leftLabel = item.labelPosition === "left";
    const bottomLabel = item.labelPosition === "bottom";
    const topLabel = item.labelPosition === "top";

    const direction =
        leftLabel ? "row-reverse" :
            bottomLabel ? "column" :
                topLabel ? "column-reverse" :
                    "row";

    /* ---------------------------------- */
    /* Content renderer                    */
    /* ---------------------------------- */
    const renderContent = () => {
        if (item.component) {
            return typeof item.component === "function"
                ? item.component({
                    selected,
                    value: item.value,
                    isInvalid: !!isInvalid,
                })
                : item.component;
        }

        return <Text fontSize={size} m={0}>{item.label}</Text>;
    };
    /* ---------------------------------- */
    /* Bulb (PrimeRadioButton) renderer    */
    /* ---------------------------------- */
    const renderBulb = () => (
        <Flex
            alignItems="center"
            gap="0.4rem"
            flexDirection={direction}
        >
            <PrimeRadioButton
                checked={selected}
                disabled={disabled}
                onChange={onToggle}
                pt={{
                    box: {
                        style: {
                            borderColor: isInvalid ? dangerColor : selected ? primaryColor : borderColor,
                            backgroundColor: isInvalid ? dangerColor : selected ? primaryColor : 'transparent',
                        }
                    },
                    icon: {
                        style: {
                            borderColor: isInvalid ? dangerColor : selected ? primaryColor : borderColor,
                        }
                    }
                }}
            />
            {renderContent()}
        </Flex>
    );

    /* ---------------------------------- */
    /* Button renderer                     */
    /* ---------------------------------- */
    const renderButton = () => (
        <Flex
            fontSize={size}
            className={`${classNames} cursor-pointer px-${item.component ? 0 : padding?.[1]} py-${item.component ? 0 : padding?.[0]}`}
            onClick={() => {
                if (!disabled) onToggle();
            }}
        >
            {renderContent()}
        </Flex>
    );

    /* ---------------------------------- */
    /* Component renderer                  */
    /* ---------------------------------- */
    const renderComponent = () => (
        <>
            {renderButton()}
            {!!item.label && <Text as="span">{item.label}</Text>}
        </>
    );

    /* ---------------------------------- */
    /* Final render                        */
    /* ---------------------------------- */
    return (
        <Text
            as="label"
            alignItems="center"
            justifyContent="center"
            w={item.w}
            pointerEvents={disabled ? "none" : "auto"}
        >
            {item.withBulbs
                ? renderBulb()
                : item.component
                    ? renderComponent()
                    : renderButton()}
        </Text>
    );
};

export default RadioButton;
